const command = $('Load Registry JSON').first().json;
const registry = command.registry || {};

function pickRaw(value) {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value;
  if (typeof value.content === 'string') return value.content;
  if (typeof value.text === 'string') return value.text;
  if (typeof value.response === 'string') return value.response;
  if (typeof value.output === 'string') return value.output;
  if (typeof value.message?.content === 'string') return value.message.content;
  if (Array.isArray(value.choices) && typeof value.choices[0]?.message?.content === 'string') return value.choices[0].message.content;
  if (Array.isArray(value.generations) && typeof value.generations[0]?.text === 'string') return value.generations[0].text;
  return JSON.stringify(value);
}

function stripCodeFence(value) {
  return String(value || '')
    .trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function extractJsonObject(text) {
  const value = stripCodeFence(text);

  try {
    return JSON.parse(value);
  } catch (_) {}

  const first = value.indexOf('{');
  const last = value.lastIndexOf('}');
  if (first !== -1 && last > first) {
    try {
      return JSON.parse(value.slice(first, last + 1));
    } catch (_) {}
  }

  return null;
}

function normalizeEmailList(value) {
  if (value === undefined || value === null || value === '') return [];

  const values = Array.isArray(value) ? value : [value];

  return values
    .flatMap((item) => {
      if (item === undefined || item === null || item === '') return [];

      if (typeof item === 'string') {
        return item.split(',');
      }

      if (typeof item === 'object') {
        return [
          item.email,
          item.address,
          item.value,
          item.text,
        ];
      }

      return [String(item)];
    })
    .map((v) => String(v || '').trim())
    .filter((v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v));
}

function normalizeBlockedChanges(value) {
  if (!value) return [];
  if (Array.isArray(value)) {
    return value.map(String).map((v) => v.trim()).filter(Boolean);
  }
  return [String(value).trim()].filter(Boolean);
}

function normalizeNewlines(value) {
  return String(value || '')
    .replace(/\\r\\n/g, '\n')
    .replace(/\\n/g, '\n')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function ensureSignature(body) {
  let value = normalizeNewlines(body);

  value = value
    .replace(/\n*Best Regards,?\s*(Guilherme)?\s*$/i, '')
    .trim();

  return `${value}\n\nBest Regards,\nGuilherme`;
}

function fallbackBodyFromFeedback() {
  const current = normalizeNewlines(registry.email_body);
  const feedback = normalizeNewlines(command.feedback);
  if (!feedback) return current;

  return ensureSignature(`${current}\n\n${feedback}`);
}

const raw = pickRaw($json);
const parsed = extractJsonObject(raw) || {};
const usedFallback = !Object.keys(parsed).length;
const invoiceToken = 'Invoice #' + registry.invoice_number;

let emailSubject = normalizeNewlines(parsed.email_subject || registry.email_subject || invoiceToken);
let emailBody = normalizeNewlines(
  parsed.email_body || (usedFallback ? fallbackBodyFromFeedback() : registry.email_body)
);

if (!emailSubject.includes(invoiceToken)) {
  emailSubject = registry.email_subject || invoiceToken;
}

if (!emailBody.includes(invoiceToken)) {
  const originalBody = normalizeNewlines(registry.email_body || '');
  if (originalBody.includes(invoiceToken)) {
    emailBody = originalBody;
  }
}

emailBody = ensureSignature(emailBody);

const parsedEmailTo = normalizeEmailList(parsed.email_to);
const registryEmailTo = normalizeEmailList(registry.email_to);

const nextEmailTo = parsedEmailTo.length ? parsedEmailTo : registryEmailTo;

const nextEmailCc = parsed.email_cc !== undefined
  ? normalizeEmailList(parsed.email_cc)
  : normalizeEmailList(registry.email_cc);

const nextEmailBcc = parsed.email_bcc !== undefined
  ? normalizeEmailList(parsed.email_bcc)
  : normalizeEmailList(registry.email_bcc);

const editEntry = {
  requested_at: new Date().toISOString(),
  feedback: command.feedback,
  change_summary: normalizeNewlines(
    parsed.change_summary ||
    (usedFallback ? 'Used deterministic fallback because AI response was not valid JSON.' : 'Updated email draft.')
  ),
  blocked_changes: normalizeBlockedChanges(parsed.blocked_changes),
  ai_response_was_json: !usedFallback,
};

const updated = {
  ...registry,
  status: 'pending_review',
  invoice_status: 'pending_review',
  email_to: nextEmailTo,
  email_cc: nextEmailCc,
  email_bcc: nextEmailBcc,
  email_subject: emailSubject,
  email_body: emailBody,
  edit_history: [...(registry.edit_history || []), editEntry],
  updated_at: new Date().toISOString(),
};

const registryText = JSON.stringify(updated, null, 2);

return {
  json: {
    ...command,
    registry: updated,
    edit_entry: editEntry,
    ai_raw_edit_response: raw,
  },
  binary: {
    registry_json: {
      data: Buffer.from(registryText, 'utf8').toString('base64'),
      fileName: 'current-invoice-state.json',
      fileExtension: 'json',
      mimeType: 'application/json',
    },
  },
};

