const item = $json;
const registry = item.registry || {};
if (item.run_id !== registry.run_id) throw new Error('Run ID mismatch. Command was ' + item.run_id + ', current registry is ' + (registry.run_id || 'empty') + '.');
if (registry.status !== 'pending_review') throw new Error('Invoice ' + (registry.invoice_number || '') + ' is not pending review. Current status: ' + (registry.status || 'unknown') + '.');
return { json: { ...item, registry, draft_drive_file_id: registry.draft_drive_file_id } };

const staticData = $getWorkflowStaticData('global');
const item = $input.first();
const inputJson = item.json || {};
const command = inputJson.command ? inputJson : staticData.latest_telegram_command;

if (!command) {
  throw new Error('Missing Telegram command context. Run this path from Telegram Trigger -> Config -> Parse Telegram Commands.');
}

const binary = item.binary || {};
const binaryPropertyName = binary.registry_json ? 'registry_json' : (binary.data ? 'data' : null);
let registry = {};

if (!binaryPropertyName) {
  throw new Error(`Missing registry binary file. Available binary fields: ${Object.keys(binary).join(', ') || '(none)'}`);
}

const buffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
const text = buffer.toString('utf8').trim();

if (text) {
  try {
    registry = JSON.parse(text);
  } catch (error) {
    throw new Error(`Current invoice registry file is not valid JSON. Confirm that current_invoice_registry_file_id points to a plain .json file, not the invoice spreadsheet/template. Parser error: ${error.message}. File starts with: ${text.slice(0, 80)}`);
  }
}

return [{
  json: {
    ...command,
    registry,
    registry_file_id: command.registry_file_id,
  },
}];

const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');
const allowedChatId = String(input.telegram_chat_id || '');
const registryFileId = input.current_invoice_registry_file_id;
let latestCommand = null;

if (!allowedChatId) {
  throw new Error('Missing telegram_chat_id. Fill it in Config.telegram_chat_id.');
}

if (!registryFileId || String(registryFileId).includes('REPLACE_WITH')) {
  throw new Error('Missing current_invoice_registry_file_id. Fill it in Config.current_invoice_registry_file_id.');
}

function parseMessage(message) {
  if (!message || !message.text) return null;
  if (String(message.chat?.id) !== allowedChatId) return null;

  const text = String(message.text || '').trim();
  const match = text.match(/^\/?(approve|reject|edit)\s+(\S+)(?:\s+([\s\S]+))?$/i);

  if (!match) {
    return {
      command: 'help',
      valid: false,
      registry_file_id: registryFileId,
      chat_id: message.chat.id,
      message_id: message.message_id,
      original_text: text,
      error: 'Use approve <run_id>, reject <run_id>, or edit <run_id> <requested changes>.',
    };
  }

  const command = match[1].toLowerCase();
  const feedback = (match[3] || '').trim();

  if (command === 'edit' && !feedback) {
    return {
      command: 'help',
      valid: false,
      registry_file_id: registryFileId,
      chat_id: message.chat.id,
      message_id: message.message_id,
      original_text: text,
      error: 'Edit requires feedback: edit <run_id> <requested changes>.',
    };
  }

  return {
    command,
    valid: true,
    run_id: match[2],
    feedback,
    registry_file_id: registryFileId,
    chat_id: message.chat.id,
    message_id: message.message_id,
    original_text: text,
  };
}

// Telegram Trigger usually emits the full update object: { update_id, message: {...} }.
if (input.message) {
  latestCommand = parseMessage(input.message);
}

// Compatibility for old polling output: { result: [{ update_id, message: {...} }] }.
if (!latestCommand && Array.isArray(input.result)) {
  for (const update of input.result) {
    const parsed = parseMessage(update.message);
    if (parsed) latestCommand = parsed;
  }
}

// Fallback if a future node emits the message directly.
if (!latestCommand && input.chat && input.text) {
  latestCommand = parseMessage(input);
}

staticData.latest_telegram_command = latestCommand || null;
return latestCommand ? [{ json: latestCommand }] : [];

const invoice = $('Recover invoice data and append PDF draft').first().json;
const telegramOutput = $json.result || $json;
const config = $('Edit Fields1').first().json;
function asArray(value) {
  if (Array.isArray(value)) return value.filter(Boolean).map(String);
  if (value === undefined || value === null || value === '') return {};
  return String(value).split(',').map((item) => item.trim()).filter(Boolean);
}
const now = new Date().toISOString();
const registry = {
  schema_version: 1,
  status: 'pending_review',
  run_id: invoice.run_id,
  invoice_number: invoice.invoice_number,
