  invoice_date: invoice.invoice_sheet_data?.invoice_date,
  due_date: invoice.invoice_sheet_data?.due_date,
  entry_count: invoice.current_invoice_data?.entry_count,
  total_minutes: invoice.current_invoice_data?.total_minutes,
  total_hours: invoice.current_invoice_data?.total_hours,
  hourly_rate: invoice.current_invoice_data?.hourly_rate,
  currency: invoice.current_invoice_data?.currency,
  amount: invoice.current_invoice_data?.amount,
  confidence: invoice.current_invoice_data?.confidence,
  recommended_action: invoice.current_invoice_data?.recommended_action,
