  binary: { registry_json: { data: Buffer.from(registryText, 'utf8').toString('base64'), fileName: 'current-invoice-state.json', fileExtension: 'json', mimeType: 'application/json' } }
};

const invoice = $('Append JSON and Invoice data').first().json;
const binary = $input.first().binary;

const fileName = `${invoice.draft_drive_file_name}.pdf`

binary.data.fileName = fileName;
binary.data.fileExtension = 'pdf';
binary.data.mimeType = 'application/pdf';

return {
