  binary
}

const invoice = $('Append JSON and Invoice data').first().json

return {
  json: invoice
}

const invoice = $input.first().json;

const rows = [
  ['invoice_number', invoice.invoice_sheet_data.invoice_number],
  ['invoice_date', invoice.invoice_sheet_data.invoice_date],
  ['due_date', invoice.invoice_sheet_data.due_date],
