const invoice = $('Normalize AI JSON').first().json;
const copiedFile = $json;

function formatDate(date) {
  return date.toISOString().slice(0, 10);
}

const today = new Date();
const invoiceDate = formatDate(today);

const due = new Date(today);
due.setDate(due.getDate() + 15);
const dueDate = formatDate(due);

const periodStart = invoice.period_start;
const periodEnd = invoice.period_end;

const periodStartDate = new Date(`${periodStart}T00:00:00`);
const periodEndDate = new Date(`${periodEnd}T00:00:00`);

const monthName = periodEndDate.toLocaleString('en-US', {
  month: 'long',
  timeZone: 'UTC',
});

const periodLabel = `${periodStartDate.getUTCDate()} to ${periodEndDate.getUTCDate()} ${monthName}`;

const currentInvoiceData = {
  run_id: invoice.run_id,
  invoice_number: invoice.invoice_number,
  invoice_status: invoice.invoice_status,
  period_label: periodLabel,
  entry_count: invoice.entry_count,
  total_minutes: invoice.total_minutes,
  total_hours: invoice.total_hours,
  hourly_rate: invoice.hourly_rate,
  currency: invoice.currency,
  amount: invoice.amount,
  confidence: invoice.confidence,
  recommended_action: invoice.recommended_action,
  detected_issues: invoice.detected_issues || [],
  email_subject: invoice.email_subject,
  email_body: invoice.email_body,
  telegram_message: invoice.telegram_message,
  draft_drive_file_id: copiedFile.id,
  draft_drive_file_name: copiedFile.name,
  invoice_date: invoiceDate,
  due_date: dueDate,
};

return {
  json: {
    current_invoice_data: currentInvoiceData,

    draft_drive_file_id: copiedFile.id,
    draft_drive_file_name: copiedFile.name,

    run_id: invoice.run_id,
    invoice_number: invoice.invoice_number,

    invoice_sheet_data: {
      invoice_number: invoice.invoice_number,
      invoice_date: invoiceDate,
      due_date: dueDate,
      period_label: periodLabel,
      hourly_rate: invoice.hourly_rate,
      quantity: invoice.total_hours,
      amount: invoice.amount,
      balance_due: invoice.amount,
    },
  },
};

const source = $('Reserve Invoice Number1').first().json;
const raw = $json.content ?? $json.text ?? $json.message?.content ?? $json.response ?? JSON.stringify($json);

function extractJsonObject(text) {
  const value = String(text || '').trim();
  try {
    return JSON.parse(value);
  } catch (_) {}

  const fenced = value.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1].trim());
    } catch (_) {}
  }

  const first = value.indexOf('{');
  const last = value.lastIndexOf('}');
  if (first !== -1 && last !== -1 && last > first) {
    return JSON.parse(value.slice(first, last + 1));
  }

  throw new Error('AI response did not contain valid JSON.');
}

function asArray(value) {
  if (Array.isArray(value)) return value.map(String).filter(Boolean);
  if (value === undefined || value === null || value === '') return [];
  return [String(value)];
}

function cleanEnum(value, allowed, fallback) {
  return allowed.includes(value) ? value : fallback;
}

function normalizeNewlines(value) {
  return String(value || '')
    .replace(/\\r\\n/g, '\n')
    .replace(/\\n/g, '\n')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function defaultEmail(invoiceNumber, hasAttachment) {
  const action = hasAttachment
    ? `Please find attached Invoice #${invoiceNumber} for the services provided. Thank you for your time.`
    : `I am sending Invoice #${invoiceNumber} for the services provided. Thank you for your time.`;

  return `Hi X and Y,\n\nI hope this email finds you well.\n\n${action}\n\nBest Regards,\nGuilherme`;
}

function containsForbiddenExternalContent(value) {
  const text = String(value || '');
  const forbiddenPatterns = [
    /\[[^\]]+\]/,
    /unknown/i,
    /invoice draft/i,
    /automation/i,
    /\bAI\b/i,
    /validation/i,
    /approval/i,
    /confidence/i,
    /detected issues/i,
    /Productive\.io/i,
    /time entries/i,
    /\bhours?\b/i,
    /\brate\b/i,
    /\bamount\b/i,
    /billing period/i,
    /services provided\s+from/i,
    /\bfrom\s+\d{1,2}\s+[A-Za-z]{3,9}\s+\d{4}\s+to\s+\d{1,2}\s+[A-Za-z]{3,9}\s+\d{4}\b/i,
    /\b\d{4}-\d{2}-\d{2}\b/,
    /\b\d{1,2}\s+(Jan|January|Feb|February|Mar|March|Apr|April|May|Jun|June|Jul|July|Aug|August|Sep|September|Oct|October|Nov|November|Dec|December)\s+\d{4}\b/i,
    /\$\s*\d/
  ];

  return forbiddenPatterns.some((pattern) => pattern.test(text));
}

function defaultTelegramMessage(source, confidence, issues) {
  const issueText = issues.length ? issues.join('; ') : 'none';
  return `Guilherme, please review Invoice #${source.invoice_number}. Period: ${source.period_start} to ${source.period_end}. Hours: ${source.total_hours}. Amount: ${source.currency} ${source.amount}. Confidence: ${confidence}. Issues: ${issueText}. Reply approve, reject, or edit.`;
}

let parsed;
let parserWarning = null;
try {
  parsed = extractJsonObject(raw);
} catch (error) {
  parserWarning = error.message;
  parsed = {};
}

const invoiceNumber = source.invoice_number;
const hasAttachment = Boolean(source.invoice_file_name || source.attachment_file_name);
let emailBody = normalizeNewlines(parsed.email_body);

if (!emailBody || !emailBody.includes(`Invoice #${invoiceNumber}`) || containsForbiddenExternalContent(emailBody)) {
  emailBody = defaultEmail(invoiceNumber, hasAttachment);
}

let emailSubject = normalizeNewlines(parsed.email_subject);
if (!emailSubject || !emailSubject.includes(`Invoice #${invoiceNumber}`) || containsForbiddenExternalContent(emailSubject)) {
  emailSubject = `Invoice #${invoiceNumber}`;
}

let recommendedAction = cleanEnum(parsed.recommended_action, ['request_approval', 'needs_manual_review', 'stop'], 'needs_manual_review');
let confidence = cleanEnum(parsed.confidence, ['high', 'medium', 'low'], 'low');
const detectedIssues = asArray(parsed.detected_issues);

if (parserWarning) {
  recommendedAction = 'needs_manual_review';
  confidence = 'low';
  detectedIssues.push(parserWarning);
}

if (!source.period_start || !source.period_end || source.amount === undefined || source.amount === null || !invoiceNumber) {
  recommendedAction = 'stop';
  confidence = 'low';
  detectedIssues.push('Essential invoice data is missing.');
}

if ((source.warnings || []).length > 0 || Number(source.entry_count || 0) === 0 || Number(source.total_hours || 0) === 0) {
  if (recommendedAction === 'request_approval') recommendedAction = 'needs_manual_review';
  if (confidence === 'high') confidence = 'medium';
}

const normalizedIssues = [...new Set(detectedIssues)];
const telegramMessage = normalizeNewlines(parsed.telegram_message) || defaultTelegramMessage(source, confidence, normalizedIssues);

const normalized = {
  confidence,
  recommended_action: recommendedAction,
  summary: normalizeNewlines(parsed.summary) || 'The invoice data was normalized for manual review.',
  detected_issues: normalizedIssues,
  work_summary: asArray(parsed.work_summary),
  telegram_message: telegramMessage,
  email_subject: emailSubject,
  email_body: emailBody
};

return {
  json: {
    ...source,
    current_invoice_data: {
      run_id: source.run_id,
      invoice_number: source.invoice_number,
      invoice_status: source.invoice_status,
      period_start: source.period_start,
      period_end: source.period_end,
      entry_count: source.entry_count,
      total_minutes: source.total_minutes,
      total_hours: source.total_hours,
      hourly_rate: source.hourly_rate,
      currency: source.currency,
      amount: source.amount,
      confidence: normalized.confidence,
      recommended_action: normalized.recommended_action,
      detected_issues: normalized.detected_issues,
      email_subject: normalized.email_subject,
      email_body: normalized.email_body,
      telegram_message: normalized.telegram_message
    },
    ai_raw_response: raw,
    ai: normalized,
    confidence: normalized.confidence,
    recommended_action: normalized.recommended_action,
    summary: normalized.summary,
    detected_issues: normalized.detected_issues,
    work_summary: normalized.work_summary,
    telegram_message: normalized.telegram_message,
    email_subject: normalized.email_subject,
    email_body: normalized.email_body
  }
};

const input = $json;
const config = $('Edit Fields1').first().json;
const staticData = $getWorkflowStaticData('global');

const initialInvoiceNumber = Number(config.initial_invoice_number || 0);
const lastInvoiceNumber = Number(staticData.last_invoice_number || initialInvoiceNumber);
const nextInvoiceNumber = lastInvoiceNumber + 1;

// Reserve immediately so approval, PDF generation, Gmail, and logs all refer to the same invoice number.
staticData.last_invoice_number = nextInvoiceNumber;

const invoiceNumber = String(nextInvoiceNumber).padStart(3, '0');
const runId = `${Date.now()}-${invoiceNumber}`;

return {
  json: {
    ...input,
    invoice_number: invoiceNumber,
    run_id: runId,
    invoice_status: 'pending_approval',
    client_names: config.client_names || 'X and Y'
  }
};

const raw = $json.data;
const body = typeof raw === "string" ? JSON.parse(raw) : $json;

const period = $("Set Billing Period1").first().json;
const entries = body.data || [];

const hourlyRate = $('Edit Fields1').item.json.hourly_rate; 
const currency = $('Edit Fields1').item.json.currency;

function stripHtml(html) {
  return String(html || "")
    .replace(/<[^>]+>/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

let totalMinutes = 0;

const cleanEntries = entries.map((entry) => {
  const attrs = entry.attributes || {};
  const minutes = attrs.time || 0;
  totalMinutes += minutes;

  return {
    id: entry.id,
    date: attrs.date,
    minutes,
    hours: Number((minutes / 60).toFixed(2)),
    note: stripHtml(attrs.note),
  };
});

const totalHours = Number((totalMinutes / 60).toFixed(2));
const amount = Number((totalHours * hourlyRate).toFixed(2));

const warnings = [];

if (entries.length === 0) {
  warnings.push("No time entries found for this period.");
}

if (body.meta?.total_pages > 1) {
  warnings.push(`Productive returned ${body.meta.total_pages} pages. Pagination is not implemented yet.`);
}

return {
    json: {
      period_start: period.period_start,
      period_end: period.period_end,
      period_source: period.period_source,
      entry_count: cleanEntries.length,
      total_minutes: totalMinutes,
      total_hours: totalHours,
      hourly_rate: hourlyRate,
      currency,
      amount,
      warnings
    },
  }

const input = $json;

if (input.period_start && input.period_end) {
  return {
    json: {
      ...input,
      period_start: input.period_start,
      period_end: input.period_end,
      period_source: "manual"
    }
  }
}

const now = new Date(input.timestamp ?? Date.now())
const year = now.getFullYear();
const month = now.getMonth();
const day = now.getDate();

function yyyyMmDd(date) {
  return date.toISOString().slice(0, 10);
}

let periodStart;
let periodEnd;
let periodSource;

if (day >= 16) {
  // On the 16th, invoice days 1-15 of the current month
  periodStart = new Date(year, month, 1);
  periodEnd = new Date(year, month, 15);
  periodSource = day === 16 ? "scheduled-day-16" : "manual";
} else {
  // On the 1st, invoice day 16 through last day of previous month
  periodStart = new Date(year, month - 1, 16);
  periodEnd = new Date(year, month, 0);
  periodSource = day === 1 ? "scheduled-day-1" : "manual";
} 

  const time = {
    json: {
      period_start: yyyyMmDd(periodStart),
      period_end: yyyyMmDd(periodEnd),
      period_source: periodSource
    }
  }

return time;
